# -*- coding: utf-8 -*-
# Daily-checks terms.
GLOSSARY_ADD = [
    {"term": "Pause point", "defn": "A named moment a short checklist is run at (lights-on, first irrigation, pre-dark), rather than one long sheet done whenever.", "tags": ["operations"]},
    {"term": "Killer item", "defn": "A check that is both easy to skip and dangerous to miss (dehumidification at lights-off, a dosing pump with no irrigation timeout). The few items a checklist must force.", "tags": ["operations"]},
    {"term": "Read-do vs do-confirm", "defn": "Two checklist styles: read-do = perform each step as you read it (setup, calibration); do-confirm = do the round from memory, then pause to confirm nothing critical was missed.", "tags": ["operations"]},
    {"term": "Pencil-whipping", "defn": "Signing off a check without actually doing it. A predictable response to a check that is too slow, unowned, or never acted on, not simply carelessness.", "tags": ["operations"]},
    {"term": "Implementation intention", "defn": "An if-then plan that ties a task to a fixed time and place ('at lights-on, the AM tech does X'), which makes follow-through 2-3x more likely.", "tags": ["operations"]},
    {"term": "Action limit", "defn": "A pre-set value that, when crossed, forces a defined response (and a corrective-action note). Paired with a softer alert limit that just warns.", "tags": ["operations", "precision"]},
    {"term": "Auto-tick (self-completing check)", "defn": "A check item that a system marks done by itself when its telemetry confirms the condition, leaving the human only the items a sensor cannot judge.", "tags": ["operations", "precision"]},
]
